func (fx *TensorboardServiceTensorboardExperimentTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		_, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
			Parent: "invalid resource name",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
			Parent:    parent,
			PageToken: "invalid page token",
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		_, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
			Parent:   parent,
			PageSize: -10,
		}))
		assert.Equal(t, connect.CodeInvalidArgument, connect.CodeOf(err), err)
	})

	{
		const resourcesCount = 15
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.TensorboardExperiment, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
				Parent:   parent,
				PageSize: 999,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.TensorboardExperiments,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TensorboardExperiment) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
				Parent:   parent,
				PageSize: resourcesCount,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Equal(t, "", response.NextPageToken)
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
				Parent:   parent,
				PageSize: resourcesCount - 1,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.Check(t, response.NextPageToken != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.TensorboardExperiment, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
					Parent:    parent,
					PageSize:  1,
					PageToken: nextPageToken,
				}))
				response := listResp.Msg
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.TensorboardExperiments))
				msgs = append(msgs, response.TensorboardExperiments...)
				nextPageToken = response.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TensorboardExperiment) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

		// Method should not return deleted resources.
		t.Run("deleted", func(t *testing.T) {
			fx.maybeSkip(t)
			const deleteCount = 5
			for i := 0; i < deleteCount; i++ {
				_, err := fx.Service().DeleteTensorboardExperiment(fx.Context(), connect.NewRequest(&aiplatformpb.DeleteTensorboardExperimentRequest{
					Name: parentMsgs[i].Name,
				}))
				assert.NilError(t, err)
			}
			listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
				Parent:   parent,
				PageSize: 9999,
			}))
			response := listResp.Msg
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs[deleteCount:],
				response.TensorboardExperiments,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TensorboardExperiment) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
	{
		const resourcesCount = 101
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*aiplatformpb.TensorboardExperiment, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// Listing resource with page size zero should eventually return all resources.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*aiplatformpb.TensorboardExperiment, 0, resourcesCount)
			var nextPageToken string
			for {
				listResp, err := fx.Service().ListTensorboardExperiments(fx.Context(), connect.NewRequest(&aiplatformpb.ListTensorboardExperimentsRequest{
					Parent:    parent,
					PageSize:  0,
					PageToken: nextPageToken,
				}))
				page := listResp.Msg
				assert.NilError(t, err)
				msgs = append(msgs, page.TensorboardExperiments...)
				nextPageToken = page.NextPageToken
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *aiplatformpb.TensorboardExperiment) bool {
					return a.Name < b.Name
				}),
				protocmp.Transform(),
			)
		})

	}
}

